"""
Difference set construction from Z_23.
A (23,11,5) cyclic difference set exists since 23 = 4*5 + 3 (Paley-Hadamard).
The incidence matrix of the symmetric (23,11,5) design gives a +1/-1 matrix
with known determinant properties.

Also try: Payley difference set D = {quadratic residues mod 23} = {1,2,3,4,6,8,9,12,13,16,18}.
Size 11. This generates the Paley core Q where Q[i,j] = 1 if (j-i) in D, -1 otherwise (for i≠j).
"""
import numpy as np

def generate_matrices():
    N = 23
    # Quadratic residues mod 23 (the difference set)
    D = {1, 2, 3, 4, 6, 8, 9, 12, 13, 16, 18}

    results = []

    # Strategy: Build the symmetric block design incidence matrix
    # M[i,j] = +1 if (j-i) mod 23 in D, -1 otherwise
    # This is Q+I from the Paley core — already explored.
    # Instead, try SHIFTED versions and COMPLEMENTARY designs.

    for shift in range(5):
        D_shifted = {(x + shift) % 23 for x in D}

        M = np.ones((N, N), dtype=np.int8)
        for i in range(N):
            for j in range(N):
                d = (j - i) % 23
                if d in D_shifted:
                    M[i, j] = 1
                elif d == 0:
                    # Diagonal: try different patterns
                    if shift % 2 == 0:
                        M[i, j] = 1
                    else:
                        M[i, j] = -1
                else:
                    M[i, j] = -1

        results.append((M, f'diffset_shift{shift}'))

    return results

# Build from Paley conference-like core with border variations
import numpy as np
from constructions import paley_core

def generate_matrices():
    Q = paley_core(23)  # 23x23 Paley core (skew-symmetric)
    results = []

    # Strategy 1: Direct Paley core with various diagonals
    for diag_pattern in range(5):
        M = Q.copy().astype(np.int8)
        # Different diagonal patterns
        if diag_pattern == 0:
            np.fill_diagonal(M, 1)
        elif diag_pattern == 1:
            np.fill_diagonal(M, -1)
        elif diag_pattern == 2:
            M[np.arange(23), np.arange(23)] = np.where(np.arange(23) % 2 == 0, 1, -1)
        elif diag_pattern == 3:
            M[np.arange(23), np.arange(23)] = np.where(np.arange(23) % 3 == 0, 1, -1)
        else:
            # All zeros on diagonal (not ±1! fix below)
            np.fill_diagonal(M, 1)

        results.append((M, f'paley_diag_{diag_pattern}'))

    return results[:5]

# Symmetric +/-1 matrices constructed from multiplicative characters mod 23.
# Unlike the Paley core (skew-symmetric), these are SYMMETRIC with
# carefully chosen sign patterns based on quadratic residues and cosets.
import numpy as np

def generate_matrices():
    N = 23
    MOD = 23
    # Quadratic residues mod 23
    qr = set()
    for i in range(1, MOD):
        qr.add(pow(i, 2, MOD))

    results = []

    for variant in range(5):
        M = np.zeros((N, N), dtype=np.int8)

        for i in range(N):
            for j in range(N):
                if i == j:
                    if variant == 0:
                        M[i, j] = 1
                    elif variant == 1:
                        M[i, j] = 1 if i in qr else -1
                    elif variant == 2:
                        M[i, j] = 1 if i % 2 == 0 else -1
                    elif variant == 3:
                        M[i, j] = 1 if i < 12 else -1
                    else:
                        # Based on multiplicative order mod 23
                        # Primitive root is 5; entries with order dividing (p-1)/2
                        M[i, j] = 1 if pow(5, i, 23) < 12 else -1
                else:
                    d = (i - j) % MOD
                    if variant == 0:
                        # Pure QR pattern (symmetric, unlike Paley)
                        M[i, j] = 1 if d in qr else -1
                    elif variant == 1:
                        # Product of Legendre symbols
                        li = 1 if (i == 0 or i in qr) else -1
                        lj = 1 if (j == 0 or j in qr) else -1
                        M[i, j] = li * lj * (1 if d in qr else -1)
                    elif variant == 2:
                        # Sum index pattern: (i+j) mod 23
                        s = (i + j) % MOD
                        M[i, j] = 1 if (s == 0 or s in qr) else -1
                    elif variant == 3:
                        # Sum-of-squares pattern
                        s = (i*i + j*j) % MOD
                        M[i, j] = 1 if (s == 0 or s in qr) else -1
                    else:
                        # Product index pattern: (i*j) mod 23
                        p = (i * j) % MOD
                        M[i, j] = 1 if (p == 0 or p in qr) else -1

        results.append((M, f"legendre_sym_v{variant}"))

    return results
